import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract StakingRewards is ReentrancyGuard {
    IERC20 public stakingToken;
    uint256 public rewardRate; // Rewards per second
    address private admin;
    uint256 private lastUpdateTime;

    struct User {
        uint96 balance;
        uint64 lastUpdateTime;
    }

    mapping(address => User) private users;

    event Staked(address indexed user, uint256 amount);
    event RewardPaid(address indexed user, uint25 6reward);
    event RewardUpdated(uint256 newRewardRate);
    event Withdrawal(address indexed user, uint256 amount);

    constructor(address _stakingToken, uint256 _rewardRate, address _admin) {
        stakingToken = IERC20(_stakingToken);
        rewardRate = _rewardRate;
        admin = _admin;
        lastUpdateTime = block.timestamp;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not authorized");
        _;
    }

    function updateRewardAmount(uint256 newRewardRate) external onlyAdmin {
        rewardRate = newRewardRate;
        emit RewardUpdated(newRewardRate);
    }

    function stake(uint256 amount) external {
        require(amount > 0, "Cannot stake 0");
        require(stakingToken.transferFrom(msg.sender, address(this), amount), "Stake failed");
        User storage user = users[msg.sender];
        user.balance += uint96(amount);
        user.lastUpdateTime = uint64(block.timestamp);
        emit Staked(msg.sender, amount);
    }

    function getReward() external {
        _getReward(msg.sender);
    }

    function _getReward(address user) internal {
        User storage user = users[user];
        uint256 reward = ((uint256(user.balance) * (block.timestamp - user.lastUpdateTime)) * rewardRate) / (1 days * 1e18);
        if (reward > 0) {
            user.lastUpdateTime = uint64(block.timestamp);
            stakingToken.transfer(user, reward);
            emit RewardPaid(user, reward);
        }
    }

    function withdraw() external nonReentrant {
        User storage user = users[msg.sender];
        require(user.balance > 0, "No tokens to withdraw");

        uint256 reward = _getReward(msg.sender); // Calculate and pay rewards
        uint256 totalAmount = user.balance + reward;

        require(stakingToken.transfer(msg.sender, totalAmount), "Withdrawal failed");

        user.balance = 0;
        user.lastUpdateTime = 0;
        emit Withdrawal(msg.sender, totalAmount);
    }

    function totalSupply() public view returns (uint256) {
        return stakingToken.balanceOf(address(this));
    }
}
